import { Link, useParams } from "react-router-dom";
import data from './data'; 

function TarjetaAmpliada(props) {
    const { id } = useParams();
    const item = props.find(i => i.id === id);

    if (!item) return <div>Producto no encontrado</div>;

    return (
        <div className="tarjeta-ampliada" key={props.id}>
            <img src={props.img} alt={props.titulo} />
            <div className="t-a-tarjeta-cont">
                <div className="t-a-texto-tarjeta">
                    <h3>{props.titulo}</h3>
                    <p>{props.precio}</p>
                    <p>{props.descripcion}</p>
                </div>
                <div className="t-a-button-cont">
                    <button><Link to={`/Productos`}>Ver Menos...</Link></button>
                    <button><img src="/add-carrito.svg" alt="Carrito" /></button>
                </div>
            </div>
        </div>
    )
}

export default TarjetaAmpliada;
